<section class="admin-page-head"><div><span class="eyebrow">Catalog</span><h1>Products</h1><p>Add products, update pricing and control availability.</p></div><a class="button button-primary" href="<?= url('admin/products/new') ?>"><i data-lucide="plus"></i>Add product</a></section><section class="admin-panel"><div class="admin-toolbar"><div class="admin-search"><i data-lucide="search"></i><input type="search" placeholder="Find a product" data-admin-product-search></div><span><?= count($products) ?> products</span></div><div class="admin-table-wrap"><table class="admin-table product-admin-table"><thead><tr><th>Product</th><th>Category</th><th>Starting price</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($products as $product): ?><tr data-admin-product data-name="<?= e(strtolower($product['name'].' '.$product['brand'])) ?>"><td><div class="product-cell"><?php if($product['image_path']): ?><img src="<?= url($product['image_path']) ?>" alt=""><?php else: ?><span><i data-lucide="image"></i></span><?php endif; ?><div><strong><?= e($product['name']) ?></strong><small><?= e($product['brand']) ?></small></div></div></td><td><?= e($product['category_name']) ?></td><td><?= money((int)$product['from_price']) ?></td><td><span class="status-pill status-<?= e($product['status']) ?>"><?= e(ucwords(str_replace('_',' ',$product['status']))) ?></span></td><td><a class="button button-small button-secondary" href="<?= url('admin/products/'.$product['id'].'/edit') ?>">Edit</a></td></tr><?php endforeach; ?></tbody></table></div></section>

